#include <stdio.h>

int main()
{
    int l,r;
    scanf("%d %d", &l, &r);
    long long a = 1, b = a, res = 0;
    while(a <= r) {
        while(b <= r) {
            if(b >= l) res++;
            b*=3;
        }
        a*=2;
        b = a;
    }
    printf("%I64d", res);
    return 0;
}

