use std::io::{self, BufRead};

fn main() {
    let reader = io::stdin();
    let numbers: Vec<i64> = 
        reader.lock()                           // (0)
              .lines().next().unwrap().unwrap() // (1)
              .split(' ').map(|s| s.trim())     // (2)
              .filter(|s| !s.is_empty())        // (3)
              .map(|s| s.parse().unwrap())      // (4)
              .collect();                       // (5)

    let l = numbers[0];
    let r = numbers[1];

    let mut ans = 0;

    let mut num2: i64 = 1;
    for p2 in 0..32 {
        let mut num3: i64 = num2;
        for p3 in 0..20 {
        	if num3 >= l && num3 <= r {
        		ans = ans + 1;
        	}
        	num3 = num3 * 3;
        }
        num2 = num2 * 2;
    }

    println!("{}", ans);
}
